mapper.select:
SELECT pr.*, pl.name AS parking_name, pl.address AS parking_address, pl.hourly_rate, ps.space_no AS space_code, ps.floor FROM parking_record pr LEFT JOIN parking_lot pl ON pr.lot_id = pl.id LEFT JOIN parking_space ps ON pr.space_id = ps.id WHERE pr.deleted = 0
AND pr.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND pr.record_status = #{recordStatus}
AND pr.entry_time >= #{entryStart}
AND pr.entry_time <= #{entryEnd}
ORDER BY pr.entry_time DESC
